def sqrt_binary_search(number, epsilon=1e-7):
    if number < 0:
        raise ValueError("Cannot compute the square root of a negative number.")
    if number == 0:
        return 0.0

    low = 0.0
    high = max(1.0, number)

    while (high - low) > epsilon:
        mid = (low + high) / 2
        mid_squared = mid * mid

        if abs(mid_squared - number) < epsilon:
            return mid
        elif mid_squared < number:
            low = mid
        else:
            high = mid

    return (low + high) / 2
